//! Global camera-motion estimation — sovereign, no-ML, integral-projection correlation.
//!
//! A panning/zooming camera makes the whole frame read as "foreground" in a static-background
//! model (every pixel changed). To recover only the RESIDUAL (object) motion we estimate the
//! dominant frame-to-frame transform and compensate for it before differencing.
//!
//! The cheap robust primitive is integral-projection correlation: collapse the luma image to a
//! row-sum profile (vertical structure) and a col-sum profile (horizontal structure), then find
//! the 1-D shift that best aligns consecutive frames' profiles. This recovers translation in
//! O(w*h + w*S + h*S) for a search radius S — far cheaper than 2-D phase correlation, and stable
//! on real footage because summing averages out per-pixel noise. A coarse scale term is recovered
//! by also aligning the profiles' second moment (profiles stretch/shrink under zoom).

/// Estimated dominant global motion between two work-resolution luma frames: a translation
/// (dx, dy) in work pixels plus a uniform scale about the frame centre (1.0 = none).
#[derive(Debug, Clone, Copy)]
pub struct GlobalMotion {
    pub dx: f32,
    pub dy: f32,
    pub scale: f32,
}

impl GlobalMotion {
    pub const IDENTITY: GlobalMotion = GlobalMotion { dx: 0.0, dy: 0.0, scale: 1.0 };
}

/// Project luma to row-sums (`rows[y]`) and col-sums (`cols[x]`), mean-centred so the
/// correlation measures shape alignment, not brightness.
fn projections(luma: &[f32], w: usize, h: usize) -> (Vec<f32>, Vec<f32>) {
    let mut rows = vec![0f32; h];
    let mut cols = vec![0f32; w];
    for y in 0..h {
        let base = y * w;
        let mut acc = 0f32;
        for x in 0..w {
            let v = luma[base + x];
            acc += v;
            cols[x] += v;
        }
        rows[y] = acc;
    }
    let rm = rows.iter().sum::<f32>() / h.max(1) as f32;
    let cm = cols.iter().sum::<f32>() / w.max(1) as f32;
    for r in rows.iter_mut() {
        *r -= rm;
    }
    for c in cols.iter_mut() {
        *c -= cm;
    }
    (rows, cols)
}

/// Best integer shift aligning `cur` onto `prev` over [-max_shift, max_shift], by normalised
/// cross-correlation of the overlapping region. Returns (shift, peak_correlation in [-1,1]).
fn best_shift(prev: &[f32], cur: &[f32], max_shift: i32) -> (i32, f32) {
    let n = prev.len() as i32;
    let mut best = 0i32;
    let mut best_corr = f32::NEG_INFINITY;
    for s in -max_shift..=max_shift {
        // Overlap where cur[i] aligns to prev[i - s] (i.e. cur shifted by +s matches prev).
        let lo = 0.max(s);
        let hi = n.min(n + s);
        if hi - lo < n / 2 {
            continue; // too little overlap to trust
        }
        let (mut dot, mut ep, mut ec) = (0f32, 0f32, 0f32);
        for i in lo..hi {
            let a = prev[(i - s) as usize];
            let b = cur[i as usize];
            dot += a * b;
            ep += a * a;
            ec += b * b;
        }
        let denom = (ep * ec).sqrt();
        let corr = if denom > 1e-6 { dot / denom } else { 0.0 };
        if corr > best_corr {
            best_corr = corr;
            best = s;
        }
    }
    (best, best_corr.max(-1.0))
}

/// Sub-pixel refine an integer correlation peak by parabolic interpolation over its neighbours.
fn refine(prev: &[f32], cur: &[f32], peak: i32, max_shift: i32) -> f32 {
    if peak <= -max_shift || peak >= max_shift {
        return peak as f32;
    }
    let c = |s: i32| -> f32 {
        let n = prev.len() as i32;
        let lo = 0.max(s);
        let hi = n.min(n + s);
        let (mut dot, mut ep, mut ec) = (0f32, 0f32, 0f32);
        for i in lo..hi {
            let a = prev[(i - s) as usize];
            let b = cur[i as usize];
            dot += a * b;
            ep += a * a;
            ec += b * b;
        }
        let d = (ep * ec).sqrt();
        if d > 1e-6 { dot / d } else { 0.0 }
    };
    let (ym1, y0, yp1) = (c(peak - 1), c(peak), c(peak + 1));
    let denom = ym1 - 2.0 * y0 + yp1;
    if denom.abs() < 1e-6 {
        return peak as f32;
    }
    peak as f32 + 0.5 * (ym1 - yp1) / denom
}

/// Estimate the dominant global motion of `cur` relative to `prev` (both work-resolution luma,
/// w*h). Returns translation in work pixels and a uniform scale. A low correlation peak (weak or
/// ambiguous global structure) collapses to the identity so we never inject spurious motion.
pub fn estimate_global_motion(prev: &[f32], cur: &[f32], w: usize, h: usize) -> GlobalMotion {
    if prev.len() != w * h || cur.len() != w * h || w == 0 || h == 0 {
        return GlobalMotion::IDENTITY;
    }
    let (prow, pcol) = projections(prev, w, h);
    let (crow, ccol) = projections(cur, w, h);

    // Search up to ~1/8 of each dimension — pans rarely exceed that per frame at work res.
    let max_x = (w as i32 / 8).max(2);
    let max_y = (h as i32 / 8).max(2);
    let (sx, cx) = best_shift(&pcol, &ccol, max_x);
    let (sy, cy) = best_shift(&prow, &crow, max_y);

    // Confidence gate: if neither axis correlates well, assume static (no global motion).
    let conf = cx.max(cy);
    if conf < 0.5 {
        return GlobalMotion::IDENTITY;
    }
    let dx = if cx >= 0.5 { refine(&pcol, &ccol, sx, max_x) } else { 0.0 };
    let dy = if cy >= 0.5 { refine(&prow, &crow, sy, max_y) } else { 0.0 };

    // Coarse scale: compare the spread (second moment) of the col profile before/after.
    let scale = estimate_scale(&pcol, &ccol, dx, w).clamp(0.95, 1.05);

    GlobalMotion { dx, dy, scale }
}

/// Uniform-scale proxy from the ratio of profile spreads about the (shifted) centroid. Profiles
/// stretch under zoom-in (scale>1) and shrink under zoom-out. Robust but coarse by design.
fn estimate_scale(prev: &[f32], cur: &[f32], dx: f32, w: usize) -> f32 {
    let center = w as f32 / 2.0;
    let spread = |p: &[f32], shift: f32| -> f32 {
        let mut num = 0f32;
        let mut den = 0f32;
        for (i, &v) in p.iter().enumerate() {
            let a = v.abs();
            let d = (i as f32 - shift) - center;
            num += a * d * d;
            den += a;
        }
        if den > 1e-6 { (num / den).sqrt() } else { 0.0 }
    };
    let sp = spread(prev, 0.0);
    let sc = spread(cur, dx);
    if sp > 1e-3 { sc / sp } else { 1.0 }
}

/// Warp `src` (w*h luma) by the inverse of `m` so it aligns to the frame `m` was measured into:
/// for each destination pixel, sample the source at where that content came from. Bilinear,
/// edge-clamped. Used to move the background model into the current frame before differencing.
pub fn warp_luma(src: &[f32], w: usize, h: usize, m: GlobalMotion) -> Vec<f32> {
    if (m.dx.abs() < 1e-3 && m.dy.abs() < 1e-3 && (m.scale - 1.0).abs() < 1e-3) || src.len() != w * h {
        return src.to_vec();
    }
    let cx = w as f32 / 2.0;
    let cy = h as f32 / 2.0;
    let mut out = vec![0f32; w * h];
    for y in 0..h {
        for x in 0..w {
            // Destination (cur frame) pixel (x,y) was, in the source (prev/bg) frame, at:
            //   src = center + (dst - center)/scale - (dx,dy)
            let sx = cx + (x as f32 - cx) / m.scale - m.dx;
            let sy = cy + (y as f32 - cy) / m.scale - m.dy;
            out[y * w + x] = sample_bilinear(src, w, h, sx, sy);
        }
    }
    out
}

/// Edge-clamped bilinear sample.
fn sample_bilinear(src: &[f32], w: usize, h: usize, x: f32, y: f32) -> f32 {
    let x = x.clamp(0.0, (w - 1) as f32);
    let y = y.clamp(0.0, (h - 1) as f32);
    let x0 = x.floor() as usize;
    let y0 = y.floor() as usize;
    let x1 = (x0 + 1).min(w - 1);
    let y1 = (y0 + 1).min(h - 1);
    let fx = x - x0 as f32;
    let fy = y - y0 as f32;
    let a = src[y0 * w + x0];
    let b = src[y0 * w + x1];
    let c = src[y1 * w + x0];
    let d = src[y1 * w + x1];
    let top = a + (b - a) * fx;
    let bot = c + (d - c) * fx;
    top + (bot - top) * fy
}

#[cfg(test)]
mod tests {
    use super::*;

    fn ramp_with_blob(w: usize, h: usize, ox: i32, oy: i32) -> Vec<f32> {
        // A smooth textured field (so projections have structure AND bilinear sampling is
        // well-defined) translated by (ox,oy).
        let mut v = vec![0f32; w * h];
        for y in 0..h {
            for x in 0..w {
                let sx = (x as i32 - ox) as f32;
                let sy = (y as i32 - oy) as f32;
                let val = 128.0
                    + 60.0 * (sx * 0.20).sin()
                    + 50.0 * (sy * 0.17).cos()
                    + 0.6 * sx
                    + 0.4 * sy;
                v[y * w + x] = val;
            }
        }
        v
    }

    #[test]
    fn recovers_pure_translation() {
        let (w, h) = (64usize, 48usize);
        let prev = ramp_with_blob(w, h, 0, 0);
        let cur = ramp_with_blob(w, h, 5, -3);
        let m = estimate_global_motion(&prev, &cur, w, h);
        assert!((m.dx - 5.0).abs() < 1.5, "dx {} != 5", m.dx);
        assert!((m.dy + 3.0).abs() < 1.5, "dy {} != -3", m.dy);
    }

    #[test]
    fn static_scene_is_identity() {
        let (w, h) = (64usize, 48usize);
        let prev = ramp_with_blob(w, h, 0, 0);
        let m = estimate_global_motion(&prev, &prev, w, h);
        assert!(m.dx.abs() < 1.0 && m.dy.abs() < 1.0, "static drift {:?}", m);
    }

    #[test]
    fn warp_then_estimate_cancels() {
        let (w, h) = (80usize, 60usize);
        let prev = ramp_with_blob(w, h, 0, 0);
        let cur = ramp_with_blob(w, h, 6, 4);
        let m = estimate_global_motion(&prev, &cur, w, h);
        // Warp prev forward into cur's frame; residual diff should be small everywhere.
        let aligned = warp_luma(&prev, w, h, m);
        let mut big = 0usize;
        for i in 0..w * h {
            if (aligned[i] - cur[i]).abs() > 20.0 {
                big += 1;
            }
        }
        let frac = big as f32 / (w * h) as f32;
        assert!(frac < 0.15, "residual after compensation too high: {:.2}", frac);
    }
}
